
  CREATE TABLE "DIRKSPZM32"."MFR_TRANSP_LOG" 
   (	"GUID" VARCHAR2(32 CHAR) DEFAULT sys_guid() NOT NULL ENABLE, 
	"LOG_DATE" DATE DEFAULT sysdate NOT NULL ENABLE, 
	"ELEMENT" VARCHAR2(50 CHAR) NOT NULL ENABLE, 
	"SOURCE" VARCHAR2(50 CHAR), 
	"TARGET" VARCHAR2(50 CHAR), 
	"TYPE" VARCHAR2(3 CHAR) DEFAULT 'BEW' NOT NULL ENABLE, 
	"LTE_ID" VARCHAR2(20 CHAR), 
	"MFR_UNIQUE_ID" VARCHAR2(50 CHAR), 
	"ORIGIN_SOURCE" VARCHAR2(50 CHAR), 
	"FINAL_DEST" VARCHAR2(50 CHAR), 
	"IS_NIO" VARCHAR2(1 CHAR) DEFAULT 'F' NOT NULL ENABLE, 
	"DURATION_SEC" NUMBER(*,3) DEFAULT 0 NOT NULL ENABLE
   ) ;
ALTER TABLE "DIRKSPZM32"."MFR_TRANSP_LOG" ADD CONSTRAINT "CHK_MFR_TRANSP_LOG_01" CHECK (type in ('BEW','POS','ARA')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_TRANSP_LOG" ADD CONSTRAINT "CHK_MFR_TRANSP_LOG_02" CHECK (is_nio in ('T', 'F')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_TRANSP_LOG" ADD CONSTRAINT "PK_MFR_TRANSP_LOG" PRIMARY KEY ("GUID")
  USING INDEX  ENABLE;


